import {useRef} from "react"
import TypeWriter from "./components/typewriter.jsx"
import {FaAdjust} from 'react-icons/fa'
import "./home.css"

function Home() {
	var welcomeH1 = useRef(0);
	var hand = useRef(0);
	document.body.classList.add("typing");
	document.body.classList.add("light");
	function doneTyping(){
		welcomeH1.current.classList.add("animate");
		hand.current.classList.add("animate");
		setTimeout(() => document.body.classList.remove("typing"),4400);
	}
	updateMode();
	function updateMode(){
		var mode = localStorage.mode;
		if(mode === "dark"){
			document.body.classList.replace("light","dark");
		}
		if(mode === "light"){
			document.body.classList.replace("dark","light");
		}
	}
	function changeMode(){
		localStorage.mode = localStorage.mode === "dark" ? "light" : "dark";
		updateMode();
	}
	return (
    	<div className="App">
			<div id='type'>
				<TypeWriter text="Hey, I'm Justin" speed={200} delay={2000} onComplete={doneTyping}/>
			</div>
			<h1 id='welcome' ref={welcomeH1}>Welcome to my website!</h1>
			<p id='hand' ref={hand}>👋</p>
			<FaAdjust onClick={changeMode} id='adjust'/>
    	</div>
  	);
}

export default Home;