import { useRef, useEffect } from 'react';
import "./typewriter.css"
function TypeWriter({text,speed,delay,onComplete}){
    var textEl = useRef(0);
    var index = 0;
    function addText(){
        if(index === 0){
            textEl.current.innerHTML = "";
        }
        if(index < text.length){
            textEl.current.innerHTML += text.charAt(index);
            setTimeout(addText,speed);
        }else{
            onComplete();
        }
        index++;
    }
    useEffect(() => {
        setTimeout(addText,delay);
    })
    return (
        <>
            <h1 className="writer" ref={textEl}> </h1>
        </>
    );
}
export default TypeWriter;